def qsort(lst):
  if len(lst)<=1: return lst
  p=lst[0]; l=[x for x in lst if x<p]; r=[x for x in lst if x>=p]
  return qsort(l)+qsort(r)

def sieve(n):
  if n<2: return []
  primes=[2]
  for i in range(3,n+1):
    if all(i%p for p in primes): primes.append(i)
  return primes

